{
	"name": "melbourne",
	"private": true,
	"scripts": {
		"build": "turbo run build --filter='*'",
		"dev": "turbo run dev --filter='*'",
		"lint": "biome check .",
		"lint:fix": "biome check --write .",
		"format": "biome format --write .",
		"check-types": "turbo run check-types --filter='*'"
	},
	"devDependencies": {
		"@biomejs/biome": "^2.4.0",
		"turbo": "^2.8.9",
		"typescript": "5.9.2"
	},
	"engines": {
		"node": ">=18"
	},
	"packageManager": "bun@1.3.5",
	"workspaces": [
		"apps/*",
		"packages/*"
	]
}

